import Marquee from 'react-fast-marquee';

function MarqueeExample() {
  return (
    <Marquee gradient={false}>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        <img src="https://via.placeholder.com/50" alt="example" />
        <span style={{ marginLeft: '10px' }}>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</span>
      </div>
    </Marquee>
  );
}
